VALUES
  ('elementary-e0adf6cd-moex-00299', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '甲老師認為學生有其主體性，教育是透過師生對話方式來協助學生自我實現，這較符合下列何種教師哲 學觀？', '["柏拉圖（Plato）「洞穴隱喻」的師生模式", "盧梭（J.J.Rousseau）「自然主義」的教學模式", "布伯（M.Buber）的「吾-汝」關係的師生模式", "赫欽斯（R.Hutchins）經典導讀的教學模式"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00300', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '「當條件化學習形成之後，如果增強物不再出現，則條件化刺激與反應之間的連結作用將會消失。」前述 說明下列何種學習現象？', '["懲罰作用", "類化作用", "辨別作用", "消弱作用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00301', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '十二年國民基本教育強調素養導向的課程與教學，教材的選擇是教師專業的必備素養，有關數學教材的選 擇，主要援引下列何項知識判準？', '["符應說（thecorrespondencetheoryoftruth）", "一致說（thecoherencetheoryoftruth）", "實效說（thepragmatictheoryoftruth）", "實證說（thepositivetheoryoftruth）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00302', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '根據皮亞傑（J.Piaget）的認知發展理論，學生運用與生俱來的思考模式或行為型式，認知並適應週遭的 環境與事物。此種與生俱來的思考模式或行為型式，皮亞傑以下列何者為名稱？', '["基模（scheme）", "本能（instinct）", "興趣（interest）", "性向（aptitude）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00303', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '「儘管家境清寒，且父母的社經背景偏低，但是學生甲奮發圖強，力爭上游，開創事業，成為人人景仰的 企業家。」此一事例最能說明社會流動的何種型態？', '["水平橫向流動", "垂直向下流動", "代內向下流動", "代間向上流動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00304', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '對於國家教育發展的規劃與推動，乙教授主張國家即使扮演著仲裁協調的角色，也應減少其干涉教育發展 的力道，容許民眾教育機會可依市場機制來分配。他的主張，與下列何種理論的思路最契合？', '["自由多元主義（LiberalPluralistTheory）", "馬克思主義（Marxism）", "新保守主義（Neo-conservatism）", "個人主義（Individualism）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00305', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '丙老師在上課時編製一些學生必須耐著性子接受、記憶與重複的內容，要求學生記錄並反覆背誦，他認為 這是最能達成教學目標的有效教學方法。前述方法比較接近弗萊勒（P.Freire）所批評的以下何種教學法？', '["合作式教學法", "批判式教學法", "囤積式教學法", "對話式教學法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
