  ('elementary-e0adf6cd-moex-00307', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '有關補救教學的論述，下列何者不適切？', '["補救的背後有水平公平、垂直公平和機會公平三種理念", "加強學生之學習策略亦是補救的可行的途徑之一", "採用評量-教學-再評量的循環歷程", "合作學習模式不適用於補救教學"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
